/**
 * ECG Simulation Catalog — Phase 2
 *
 * 250 ECG simulations across 5 professions (50 each):
 *   RN · RPN · NP · RT · New Grad
 *
 * CONTENT TIERS
 *   Flagship (20): Full data — complete progression graph, all decision
 *                  points, documentation tasks, full debrief.
 *   Standard (50): Full metadata + skeleton progression (2 nodes) +
 *                  1 decision point + debrief summary.
 *   Index (180):   Full metadata only (id, title, summary, profession,
 *                  environment, patient profile, domain tags).
 *                  Content populated in subsequent sprints.
 *
 * INTEGRATION
 *   - Hooks into EcgSimulationRecord (ecg-simulation-schema.ts)
 *   - primaryDomains reference EcgCompetencyDomainId (ecg-competency-domains.ts)
 *   - rhythmProgression.rhythmKey matches ECG_RHYTHM_TEMPLATES
 *   - decisionPoints map to EcgSimulationDecisionType
 *
 * GOVERNANCE
 *   ecg-phase2-governance.contract.test.ts enforces:
 *   - ≥50 published simulations per profession
 *   - All published flagship simulations pass validateEcgSimulation()
 *   - Life-threatening rhythm sims have code-blue decision point
 */

import type { EcgSimulationRecord, EcgSimulationProfession } from "@/lib/ecg-module/ecg-simulation-schema";

// ─── Helper to build skeleton simulations ─────────────────────────────────────

function skeletonSim(
  id: string,
  title: string,
  summary: string,
  professions: ReadonlyArray<EcgSimulationProfession>,
  rhythmKey: string,
  targetRhythmKey: string,
  specialty: EcgSimulationRecord["environment"]["specialty"],
  unitLabel: string,
  age: number,
  admissionDx: string,
  difficulty: 1 | 2 | 3 | 4 | 5,
  domains: EcgSimulationRecord["primaryDomains"],
): EcgSimulationRecord {
  return {
    id,
    title,
    summary,
    publishStatus: "review",
    targetProfessions: professions,
    environment: {
      specialty,
      unitLabel,
      monitorContext: "bedside_monitor",
      timeOfDay: "day",
      staffingContext: "adequate",
    },
    patient: {
      age,
      sex: "male",
      admissionDiagnosis: admissionDx,
      admissionReason: `Admitted for monitoring of ${admissionDx}`,
      relevantHistory: ["Hypertension", "Type 2 diabetes"],
      medications: ["Metoprolol 25 mg BID", "Aspirin 81 mg daily"],
      allergies: ["NKDA"],
      baselineRhythmKey: rhythmKey,
      baselineVitals: { hr: 72, sbp: 128, dbp: 82, spo2: 97, rr: 16 },
    },
    rhythmProgression: [
      {
        nodeId: "start",
        rhythmKey,
        onsetSeconds: 0,
        vitals: { hr: 72, sbp: 128, spo2: 97 },
        clinicalSigns: ["Patient alert and oriented", "Comfortable at rest"],
        activeAlarms: [],
        riskLevel: "low",
        missableWarnings: [],
        transitions: [{ targetNodeId: "deterioration", trigger: "no_action", label: "Rhythm changes", scoreImpact: 0 }],
      },
      {
        nodeId: "deterioration",
        rhythmKey: targetRhythmKey,
        onsetSeconds: 120,
        vitals: { hr: 145, sbp: 96, spo2: 94 },
        clinicalSigns: ["Patient diaphoretic", "Reports palpitations"],
        activeAlarms: ["Heart rate alarm — high"],
        riskLevel: "high",
        missableWarnings: ["HR trending up over preceding 20 minutes", "Single ectopic beats before sustained rhythm"],
        transitions: [],
      },
    ],
    decisionPoints: [
      {
        atNodeId: "deterioration",
        decisionType: "escalation",
        stem: `The monitor alarms. The patient is now in ${targetRhythmKey.replace(/_/g, " ")}. What is your first action?`,
        ngnFormat: "mcq",
        options: [
          { id: "a", text: "Assess the patient at the bedside", correct: true, consequenceNodeId: "deterioration", rationale: "Assessment first — confirm the patient's clinical status before acting on the monitor." },
          { id: "b", text: "Call the provider immediately without assessing", correct: false, consequenceNodeId: "deterioration", rationale: "Assessment precedes escalation — you need clinical data for the provider call." },
          { id: "c", text: "Adjust the monitor alarms to silence", correct: false, consequenceNodeId: "deterioration", rationale: "Never silence a new rhythm alarm without identifying the cause.", safetyFlag: "Silencing alarms without assessment is a safety failure." },
          { id: "d", text: "Administer PRN lorazepam for anxiety", correct: false, consequenceNodeId: "deterioration", rationale: "A pharmacologic intervention before assessment is premature and potentially harmful." },
        ],
        timeLimitSeconds: 60,
      },
    ],
    documentationTasks: [],
    debrief: {
      clinicalNarrative: `This simulation demonstrates the progression from ${rhythmKey.replace(/_/g, " ")} to ${targetRhythmKey.replace(/_/g, " ")}. Early warning signs were present but subtle.`,
      missedWarnings: ["Subtle HR trend upward in the 20 minutes before the rhythm change", "Occasional ectopic beats foreshadowing the sustained rhythm"],
      preventionOpportunities: ["Proactive assessment when HR trended upward", "Provider notification at first ectopic beat in high-risk patient"],
      learningObjectives: [`Recognize ${targetRhythmKey.replace(/_/g, " ")} and apply appropriate escalation`, "Identify early warning signs before rhythm deterioration"],
      clinicalPearls: [`${targetRhythmKey.replace(/_/g, " ")} rarely appears without warning — look for the prodrome`, "Assessment before escalation produces better clinical information"],
      guidelineReferences: ["AHA ACLS Provider Manual 2020"],
    },
    primaryDomains: domains,
    estimatedMinutes: 15,
    difficulty,
    requiresCodeBlueDecision: false,
    requiresStemiActivation: false,
    criticalSafetyDecisions: [],
  };
}

