// ─── Accessor functions ────────────────────────────────────────────────────────

export function getEcgSimulation(id: string): EcgSimulationRecord | undefined {
  return ECG_SIMULATION_CATALOG.find((s) => s.id === id);
}

export function getSimulationsForProfession(
  profession: EcgSimulationProfession,
): ReadonlyArray<EcgSimulationRecord> {
  return ECG_SIMULATION_CATALOG.filter((s) => s.targetProfessions.includes(profession));
}

export function getPublishedSimulations(): ReadonlyArray<EcgSimulationRecord> {
  return ECG_SIMULATION_CATALOG.filter((s) => s.publishStatus === "published");
}

export const SIMULATION_IDS: ReadonlyArray<string> = ECG_SIMULATION_CATALOG.map((s) => s.id);

export const CATALOG_COUNTS: Record<EcgSimulationProfession, number> = {
  RN: getSimulationsForProfession("RN").length,
  RPN: getSimulationsForProfession("RPN").length,
  NP: getSimulationsForProfession("NP").length,
  RT: getSimulationsForProfession("RT").length,
  new_grad: getSimulationsForProfession("new_grad").length,
};
